import React from 'react';
import './GridItem.css';

export default function GridItem(props) {
    return (props.trigger) ? (
    <div className="grid-item">
        { props.children }
        <break></break>
        <button onClick={() => props.setTrigger(true)}/>
    </div>
    ) : "";
}
